// frontend/src/App.js
import React from "react";
import SubmitComplaint from "./SubmitComplaint";

function App() {
  const studentToken = "PASTE_YOUR_STUDENT_TOKEN_HERE"; // get from login

  return (
    <div>
      <h1>Welcome to HostelOps</h1>
      <SubmitComplaint token={studentToken} />
    </div>
  );
}

export default App;
